questionvariables.text:
/* 1. Randomize the radius OA (between 5 and 15) */
r: 5 + rand(11);

/* 2. Constants for an Octagon */
n: 8;
central_angle: 360/n;
rad_angle: float((central_angle * %pi) / 180);

/* 3. Calculate Area of one triangle: 1/2 * r * r * sin(45) */
area_tri_exact: (1/2) * r^2 * sin(rad_angle);
area_tri: float(area_tri_exact);

/* 4. Total Area of Octagon */
ta_exact: n * area_tri_exact;
ta_1: float(ta_exact);
ta:decimalplaces(ta_1,2)
